const data = items[0].json;
const articles = data.articles;
if (!articles || articles.length === 0) return [];

const BATCH_SIZE = 20;

// Group by user_id
const byUser = {};
for (const a of articles) {
  if (!byUser[a.user_id]) {
    byUser[a.user_id] = { user_id: a.user_id, scoring_prompt: a.scoring_prompt, articles: [] };
  }
  byUser[a.user_id].articles.push(a);
}

// Cap each user to BATCH_SIZE
const result = [];
for (const group of Object.values(byUser)) {
  const batch = group.articles.slice(0, BATCH_SIZE);
  result.push({
    json: {
      user_id: group.user_id,
      scoring_prompt: group.scoring_prompt,
      article_count: batch.length,
      article_list: batch.map((a, i) =>
        `${i + 1}. id=${a.article_id} | ${a.title} | ${(a.description || '').slice(0, 150)}`
      ).join('\n'),
    }
  });
}
return result;
